import anthropic
import json

client = anthropic.Anthropic()

# ---------------------------------------------------------------------------
# Tool with a detailed, constrained schema
# ---------------------------------------------------------------------------
CREATE_TICKET_TOOL = {
    "name": "create_support_ticket",
    "description": (
        "Creates a support ticket in the ticketing system. Use when the user's issue "
        "cannot be resolved by information alone and requires follow-up action. "
        "Returns the new ticket ID."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "title": {
                "type": "string",
                "description": "A short, specific title for the issue (max 80 characters).",
                "maxLength": 80,
            },
            "description": {
                "type": "string",
                "description": "Full description of the problem, including steps to reproduce if applicable.",
            },
            "priority": {
                "type": "string",
                "enum": ["low", "medium", "high", "critical"],
                "description": (
                    "Urgency level. Use 'critical' only for complete service outages or "
                    "security incidents. Use 'high' for functionality that is broken and "
                    "blocking the user's core workflow."
                ),
            },
            "category": {
                "type": "string",
                "enum": ["billing", "technical", "account", "feature-request", "other"],
                "description": "The category that best fits the issue.",
            },
            "affected_user_id": {
                "type": "string",
                "description": "The ID of the user experiencing the issue, if known.",
            },
        },
        "required": ["title", "description", "priority", "category"],
    },
}


def create_support_ticket(**kwargs) -> dict:
    # Simulated — in production this would POST to a ticketing API
    return {"ticket_id": "TKT-9921", "status": "created", **kwargs}


def run(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=400,
        tools=[CREATE_TICKET_TOOL],
        messages=messages,
    )

    if response.stop_reason == "tool_use":
        for block in response.content:
            if block.type == "tool_use" and block.name == "create_support_ticket":
                result = create_support_ticket(**block.input)
                print(f"Tool called with: {json.dumps(block.input, indent=2)}")
                # Send result back to model for final response
                messages.append({"role": "assistant", "content": response.content})
                messages.append({"role": "user", "content": [
                    {"type": "tool_result", "tool_use_id": block.id,
                     "content": json.dumps(result)}
                ]})
                final = client.messages.create(
                    model="claude-haiku-4-5-20251001",
                    max_tokens=200,
                    tools=[CREATE_TICKET_TOOL],
                    messages=messages,
                )
                return next(b.text for b in final.content if hasattr(b, "text"))

    return next(b.text for b in response.content if hasattr(b, "text"))


print(run(
    "My account has been locked and I can't access any of my data. "
    "I need this fixed urgently — my whole team is blocked."
))

import anthropic
import json

client = anthropic.Anthropic()

# Tool with nested objects and arrays in its schema
BULK_EMAIL_TOOL = {
    "name": "send_bulk_email",
    "description": (
        "Sends a templated email to a list of recipients. "
        "Use only after explicit user confirmation. Max 50 recipients per call."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "recipients": {
                "type": "array",
                "description": "List of recipient objects. Maximum 50 items.",
                "maxItems": 50,
                "items": {
                    "type": "object",
                    "properties": {
                        "email": {
                            "type": "string",
                            "format": "email",
                            "description": "Recipient email address.",
                        },
                        "name": {
                            "type": "string",
                            "description": "Recipient display name for personalisation.",
                        },
                    },
                    "required": ["email"],
                },
            },
            "subject": {
                "type": "string",
                "description": "Email subject line (max 100 characters).",
                "maxLength": 100,
            },
            "body_template": {
                "type": "string",
                "description": (
                    "Email body. Use {{name}} as a placeholder for recipient name. "
                    "Plain text only; no HTML."
                ),
            },
            "send_at": {
                "type": "string",
                "format": "date-time",
                "description": "ISO 8601 datetime to schedule delivery. Omit to send immediately.",
            },
        },
        "required": ["recipients", "subject", "body_template"],
    },
}


response = client.messages.create(
    model="claude-haiku-4-5-20251001",
    max_tokens=300,
    tools=[BULK_EMAIL_TOOL],
    messages=[{
        "role": "user",
        "content": (
            "Send a welcome email with subject 'Welcome aboard!' to alice@example.com (Alice) "
            "and bob@example.com. Body: 'Hi {{name}}, thanks for joining us!'"
        ),
    }],
)

for block in response.content:
    if block.type == "tool_use":
        print(f"Tool: {block.name}")
        print(f"Input: {json.dumps(block.input, indent=2)}")
